code = """import json

# Count volatile days helper
def count_volatile_days(data):
    if not data:
        return 0
    
    volatile_count = 0
    for row in data:
        try:
            high = float(row.get('High', 0))
            low = float(row.get('Low', 0))
            if low > 0 and (high - low) / low > 0.20:
                volatile_count += 1
        except:
            continue
    return volatile_count

# Get all available query results
available_results = {}

# Add existing results
existing = {"AGMH": 13, "ALACU": 0, "BCLI": 0, "BHAT": 10, "BIOC": 21, "FTFT": 21, "STKS": 0, "AMHC": 0}
available_results.update(existing)

# Check if CORV, CUBA, IDEX data exists (we queried these in follow-ups)
try:
    corv_data = locals()['var_functions.query_db:72'] if 'var_functions.query_db:72' in locals() else []
    corv_count = count_volatile_days(corv_data)
    available_results["CORV"] = corv_count
except:
    pass

# Get tickers list
tickers_info = locals()['var_functions.execute_python:50']
all_tickers = tickers_info['tickers']

remaining = [t for t in all_tickers if t not in available_results]

print("Current results:", len(available_results))
print("Remaining:", len(remaining))
print("Top results so far:")
sorted_results = sorted(available_results.items(), key=lambda x: x[1], reverse=True)
for ticker, count in sorted_results[:10]:
    print(f"  {ticker}: {count} volatile days")

print('__RESULT__:')
print(json.dumps(sorted_results, indent=2))"""

